classDiagram
    class BaseRepository {
        #_session: Session
        #_model: Type
        +find_by_id(id: int)
        +find_all() list
        +save(entity)
        +delete(id: int)
        +count() int
    }
    class UserRepository {
        +find_by_email(email: str)
        +find_active() list
    }
    class OrderRepository {
        +find_by_user(user_id: int) list
        +find_pending() list
    }
    BaseRepository <|-- UserRepository
    BaseRepository <|-- OrderRepository

classDiagram
    class EventBus {
        -_handlers: dict
        +subscribe(event_type: str, handler)
        +unsubscribe(event_type: str, handler)
        +publish(event: Event)
        +clear()
    }
    class Event {
        +name: str
        +payload: dict
        +timestamp: datetime
    }
    class EventHandler {
        +handle(event: Event)
    }
    EventBus --> Event : publishes
    EventBus --> EventHandler : notifies
